#include<bits/stdc++.h>
using namespace std;
int dp[100001], n, weight;
int a[200000];
int main() {
	cin >> weight >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= n; i++) {
		for (int j = weight; j >=  a[i]; j--) {
			 dp[j] = max(a[i] + dp[j - a[i]], dp[j]);
		}
	}
	cout<<dp[weight];
	return 0;
}
